if (!msg.payload || msg.payload.valor_sensor === undefined) {
    return null;
}

let valor = Number(msg.payload.valor_sensor);
let status = msg.payload.status || "DESCONHECIDO";
let limiteMin = Number(msg.payload.limite_min);
let limiteMax = Number(msg.payload.limite_max);

if (status === "NORMAL") status = "🟢 NORMAL";
if (status === "BAIXO") status = "🟡 BAIXO";
if (status === "ALTO") status = "🔴 ALTO";

let hora = new Date().toLocaleTimeString("pt-BR");

let msg1 = { payload: valor };
let msg2 = { payload: status };
let msg3 = {
    topic: "Luminosidade",
    payload: valor,
    timestamp: Date.now()
};
let msg4 = { payload: limiteMin };
let msg5 = { payload: limiteMax };
let msg6 = { payload: valor };
let msg7 = { payload: hora };

return [msg1, msg2, msg3, msg4, msg5, msg6, msg7];

let d = msg.payload;

// segurança extra caso venha string
if (typeof d === "string") {
    d = JSON.parse(d);
}

// validação
if (!d || d.valor_sensor === undefined || d.limite_min === undefined || d.limite_max === undefined || d.status === undefined) {
    node.error("Payload inválido para INSERT: " + JSON.stringify(msg.payload), msg);
    return null;
}

msg.topic = "INSERT INTO monitoramento_luz (valor_sensor, limite_min, limite_max, status) VALUES (" +
    Number(d.valor_sensor) + ", " +
    Number(d.limite_min) + ", " +
    Number(d.limite_max) + ", '" +
    String(d.status) + "')";

return msg;

if (!msg.payload || !Array.isArray(msg.payload) || msg.payload.length === 0) {
    msg.payload = "Sem dados";
    return msg;
}

const ultimo = msg.payload[0];

let status = String(ultimo.status || "DESCONHECIDO");
let valor = Number(ultimo.valor_sensor || 0);

if (status === "NORMAL") status = "🟢 NORMAL";
if (status === "BAIXO") status = "🟡 BAIXO";
if (status === "ALTO") status = "🔴 ALTO";

msg.payload = `${status} (${valor})`;

return msg;

if (!msg.payload || !Array.isArray(msg.payload)) {
    msg.payload = [];
    return msg;
}

msg.payload = msg.payload.map(r => {
    const data = new Date(r.data_registro);

    return {
        Hora: data.toLocaleTimeString("pt-BR"),
        Valor: Number(r.valor_sensor),
        Min: Number(r.limite_min),
        Max: Number(r.limite_max),
        Status: String(r.status)
    };
});

return msg;

let saida = [];

msg.payload.forEach(r => {

    saida.push({
        topic: "Luminosidade",
        payload: Number(r.valor_sensor),
        timestamp: new Date(r.data_registro).getTime()
    });

});

return [saida];

let statusAtual = msg.payload.status;
let valorAtual = Number(msg.payload.valor_sensor || 0);

// recuperar último status salvo
let ultimoStatus = flow.get("ultimoStatusEvento");

// primeira leitura: apenas salvar na memória
if (ultimoStatus === undefined) {
    flow.set("ultimoStatusEvento", statusAtual);
    return null;
}

// se não mudou, não grava evento
if (statusAtual === ultimoStatus) {
    return null;
}

// atualizar memória
flow.set("ultimoStatusEvento", statusAtual);

// criar descrição do evento
let eventoTexto = `Mudança de ${ultimoStatus} para ${statusAtual}`;

// montar SQL
msg.topic = `
INSERT INTO eventos_luz (evento, valor_sensor, status)
VALUES ('${eventoTexto}', ${valorAtual}, '${statusAtual}')
`;

return msg;

if (!msg.payload || !Array.isArray(msg.payload)) {
    msg.payload = [];
    return msg;
}

msg.payload = msg.payload.map(r => {
    const data = new Date(r.data_evento);

    return {
        Hora: data.toLocaleTimeString("pt-BR"),
        Evento: String(r.evento),
        Valor: Number(r.valor_sensor),
        Status: String(r.status)
    };
});

return msg;

msg.payload = {
    page: "Eventos"
};
return msg;

msg.payload = {
    page: "Home"
};
return msg;

let status = String(msg.payload.status || "DESCONHECIDO");
let valor = Number(msg.payload.valor_sensor || msg.payload.valor || 0);
let periodo = String(msg.payload.periodo || "MONITORAMENTO");
let alertaNoturno = msg.payload.alerta === true;
let statusNoturno = String(msg.payload.status_noturno || "N/A");
let agora = Date.now();

// intervalo entre reenvios
let intervaloReenvio = 2 * 60 * 1000; // 2 minutos

// estados salvos
let inicioAnomalia = flow.get("inicioAnomalia") || 0;
let ultimoEnvio = flow.get("ultimoEnvioAlerta") || 0;
let ultimaChave = flow.get("ultimaChaveAlerta") || "NORMAL";
let repeticoes = flow.get("repeticoesAlerta") || 0;

// define condição de alerta
let anomalia = false;
let chaveAtual = "NORMAL";
let motivo = "";

// ===============================
// REGRA DO PROJETO
// ===============================
// À noite: só alertar por luz indevida
// De dia: alertar por BAIXO ou ALTO
if (periodo === "ESCURIDAO") {
    if (alertaNoturno && statusNoturno === "LUZ INDEVIDA") {
        anomalia = true;
        chaveAtual = "LUZ_INDEVIDA";
        motivo = "Luz indevida no período de escuridão";
    }
} else {
    if (status === "BAIXO") {
        anomalia = true;
        chaveAtual = "BAIXO";
        motivo = "Condição crítica detectada";
    } else if (status === "ALTO") {
        anomalia = true;
        chaveAtual = "ALTO";
        motivo = "Condição crítica detectada";
    }
}

// se não houver anomalia, reseta
if (!anomalia) {
    flow.set("inicioAnomalia", 0);
    flow.set("ultimoEnvioAlerta", 0);
    flow.set("ultimaChaveAlerta", "NORMAL");
    flow.set("repeticoesAlerta", 0);

    msg.payload = {
        alerta: false,
        status: status,
        valor: valor,
        repeticoes_5min: 0,
        tempo_critico_seg: 0,
        motivo: ""
    };
    return msg;
}

// primeira ocorrência ou mudança de tipo de alerta
if (inicioAnomalia === 0 || chaveAtual !== ultimaChave) {
    inicioAnomalia = agora;
    ultimoEnvio = agora;
    repeticoes = 1;

    flow.set("inicioAnomalia", inicioAnomalia);
    flow.set("ultimoEnvioAlerta", ultimoEnvio);
    flow.set("ultimaChaveAlerta", chaveAtual);
    flow.set("repeticoesAlerta", repeticoes);

    msg.payload = {
        alerta: true,
        status: chaveAtual === "LUZ_INDEVIDA" ? "CRITICO" : status,
        valor: valor,
        repeticoes_5min: repeticoes,
        tempo_critico_seg: 0,
        motivo: motivo
    };
    return msg;
}

// continua em anomalia
let tempoCriticoSeg = Math.floor((agora - inicioAnomalia) / 1000);
repeticoes = Math.floor((agora - inicioAnomalia) / (5 * 1000)) + 1;

// reenviar após intervalo
if ((agora - ultimoEnvio) >= intervaloReenvio) {
    flow.set("ultimoEnvioAlerta", agora);
    flow.set("repeticoesAlerta", repeticoes);

    msg.payload = {
        alerta: true,
        status: chaveAtual === "LUZ_INDEVIDA" ? "CRITICO" : status,
        valor: valor,
        repeticoes_5min: repeticoes,
        tempo_critico_seg: tempoCriticoSeg,
        motivo: motivo
    };
    return msg;
}

// ainda não chegou a hora de reenviar
msg.payload = {
    alerta: false,
    status: chaveAtual === "LUZ_INDEVIDA" ? "CRITICO" : status,
    valor: valor,
    repeticoes_5min: repeticoes,
    tempo_critico_seg: tempoCriticoSeg,
    motivo: motivo
};

return msg;

let alerta = msg.payload;

msg.topic = "🚨 Alerta crítico - LumiLab IoT";

msg.payload = `
ALERTA CRÍTICO DETECTADO

Status: ${alerta.status}
Valor do sensor: ${alerta.valor}
Repetições nos últimos 5 min: ${alerta.repeticoes_5min}
Tempo crítico: ${alerta.tempo_critico_seg}s

Verificar o ambiente monitorado imediatamente.
`;

return msg;

let alerta = msg.payload;

let motivo = alerta.motivo || "Condição crítica detectada";

// guarda os dados originais para usar depois no banco
msg.alertaOriginal = {
    status: alerta.status,
    valor: alerta.valor,
    repeticoes_5min: alerta.repeticoes_5min,
    tempo_critico_seg: alerta.tempo_critico_seg,
    motivo: motivo
};

msg.payload = {
    chatId: 6368155069,
    type: "message",
    content:
        "🚨 ALERTA CRÍTICO - LumiLab IoT\n\n" +
        "Motivo: " + motivo + "\n" +
        "Status: " + alerta.status + "\n" +
        "Valor: " + alerta.valor + "\n" +
        "Repetições em 5 min: " + alerta.repeticoes_5min + "\n" +
        "Tempo crítico: " + alerta.tempo_critico_seg + "s\n\n" +
        "Verificar o ambiente imediatamente."
};

return msg;

if (!msg.alertaOriginal) {
    node.error("Dados do alerta original não encontrados", msg);
    return null;
}

let alerta = msg.alertaOriginal;
let mensagem = msg.payload && msg.payload.content ? msg.payload.content : "";

msg.topic = `
INSERT INTO alertas_enviados
(canal, status, valor_sensor, motivo, repeticoes_5min, tempo_critico_seg, destinatario, mensagem)
VALUES
(
    'Telegram',
    '${String(alerta.status).replace(/'/g, "''")}',
    ${Number(alerta.valor)},
    '${String(alerta.motivo).replace(/'/g, "''")}',
    ${Number(alerta.repeticoes_5min)},
    ${Number(alerta.tempo_critico_seg)},
    'Responsável Telegram',
    '${String(mensagem).replace(/'/g, "''")}'
)
`;

return msg;

let alertas = Array.isArray(msg.payload) ? msg.payload : [];

// ordena do mais novo para o mais antigo usando o campo correto
alertas.sort((a, b) => new Date(b.data_alerta) - new Date(a.data_alerta));

// mantém só os últimos 3
alertas = alertas.slice(0, 3);

// formata para o template
msg.payload = alertas.map(a => {
    const data = a.data_alerta ? new Date(a.data_alerta) : null;

    return {
        "Status": a.status || "N/A",
        "Valor": a.valor_sensor ?? a.valor ?? 0,
        "Motivo": a.motivo || "N/A",
        "Repeticoes": a.repeticoes_5min ?? a.repeticoes ?? 0,
        "Tempo (s)": a.tempo_critico_seg ?? a.tempo_critico ?? 0,
        "Canal": a.canal || "Telegram",
        "Data": data ? data.toLocaleDateString("pt-BR") : "-",
        "Hora": data ? data.toLocaleTimeString("pt-BR") : "-"
    };
});

return msg;

msg.payload.periodo = msg.payload.periodo || "MONITORAMENTO";
msg.payload.hora_atual = msg.payload.hora_atual ?? 0;
msg.payload.alerta = msg.payload.alerta ?? false;
msg.payload.status_noturno = msg.payload.status_noturno || "N/A";

if (msg.payload.periodo === "ESCURIDAO") {
    return [msg, msg];
} else {
    return [msg, null];
}

if (msg.payload.periodo === "ESCURIDAO") {
    msg.payload = "🌙 Período de escuridão";
} else {
    msg.payload = "🟡 Período de monitoramento normal";
}

return msg;

if (msg.payload.periodo === "ESCURIDAO") {
    msg.payload = "⏸ STAND-BY";
} else {
    msg.payload = "▶ MONITORAMENTO ATIVO";
}

return msg;

if (msg.payload.periodo === "ESCURIDAO") {
    if (msg.payload.alerta === true) {
        msg.payload = "🚨 Luz indevida no período noturno";
    } else {
        msg.payload = "🌙 Escuridão dentro do esperado";
    }
} else {
    msg.payload = "";
}

return msg;

let alerta = msg.payload;

msg.payload = {
    chatId: 6368155069,
    type: "message",
    content:
        "🚨 ALERTA NOTURNO - LumiLab IoT\n\n" +
        "Período: " + alerta.periodo + "\n" +
        "Status noturno: " + alerta.status_noturno + "\n" +
        "Valor detectado: " + alerta.valor_sensor + "\n" +
        "Horário: " + alerta.hora_atual + "h\n\n" +
        "Foi detectada luminosidade indevida no período de escuridão."
};

return msg;

let valor = Number(msg.payload.valor_sensor || 0);
let motivo = (msg.payload.motivo || "").replace(/'/g, "''");
let status = (msg.payload.status_noturno || "").replace(/'/g, "''");

msg.topic = `
INSERT INTO eventos (evento, valor, status)
VALUES ('${motivo}', ${valor}, '${status}')
`;

return msg;

let alertaAtual = msg.payload.alerta === true;

// estado anterior salvo
let alertaAnterior = flow.get("alerta_noturno_ativo") || false;

// se acabou de entrar em alerta: envia
if (alertaAtual && !alertaAnterior) {
    flow.set("alerta_noturno_ativo", true);
    return msg;
}

// se voltou ao normal: reseta o estado
if (!alertaAtual && alertaAnterior) {
    flow.set("alerta_noturno_ativo", false);
}

// em qualquer outro caso, não envia nada
return null;

let dados = global.get("dados_luminosidade");

msg.statusCode = 200;
msg.headers = {
    "Content-Type": "application/json"
};

if (!dados) {
    msg.payload = {
        sistema: "LumiLab IoT",
        status: "aguardando_dados",
        mensagem: "Nenhum dado recebido ainda do sensor"
    };
    return msg;
}

msg.payload = {
    sistema: "LumiLab IoT",
    status: "online",
    timestamp: new Date().toISOString(),
    dados: dados
};

return msg;

