msg.statusCode = 200;
msg.headers = {
    "Content-Type": "application/json"
};

if (!dados) {
    msg.payload = {
        sistema: "LumiLab IoT",
        status: "aguardando_dados",
        mensagem: "Nenhum dado disponível"
